export const COLOR_THEME_DEFINITIONS: Record<BuiltInColorTheme, ColorThemeDefinition> = {
  "t3-light": T3_LIGHT,
  "t3-dark": T3_DARK,
  "t3-midnight": T3_MIDNIGHT,
