// Helper: given a BuiltInColorTheme, return the ColorThemeDefinition
export function getColorThemeDefinition(id: BuiltInColorTheme): ColorThemeDefinition {
  return COLOR_THEME_DEFINITIONS[id];
}

// Helper: resolve "system" to a concrete BuiltInColorTheme
export function resolveColorTheme(
  preference: ColorThemePreference,
  systemIsDark: boolean,
): BuiltInColorTheme {
  if (preference === "system") {
    return systemIsDark ? "t3-dark" : "t3-light";
  }
  return preference;
}
