### Step 4: `apps/web/src/hooks/useColorTheme.ts`

This follows the exact same external store pattern as the existing `useTheme.ts`. Critical: the existing `useTheme.ts` is **not modified**. The settings page will consume `useColorTheme` in addition to `useTheme` for the new granular color choices.

```typescript
import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type BuiltInColorTheme,
  type ColorThemePreference,
  COLOR_THEME_DEFINITIONS,
  resolveColorTheme,
} from "@t3tools/shared/theme";

// --- Constants ---
const STORAGE_KEY = "t3code:color-theme";
const OLD_STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// --- Module-level store state ---
let listeners: Array<() => void> = [];
let lastSnapshot: { preference: ColorThemePreference; systemDark: boolean } | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function migrateFromOldKey(): ColorThemePreference {
  // Read old key, migrate value, write to new key, remove old key
  const old = localStorage.getItem(OLD_STORAGE_KEY);
  if (!old) return "system";
  const migrated: ColorThemePreference =
    old === "dark" ? "t3-dark" :
    old === "light" ? "t3-light" :
    "system";
  localStorage.setItem(STORAGE_KEY, migrated);
  // NOTE: do NOT remove the old key — useTheme.ts still reads it for .dark class logic.
  // The old key is left intact so the existing hook continues working independently.
  return migrated;
}

function getStoredPreference(): ColorThemePreference {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight" || raw === "system") {
    return raw;
  }
  // First run: migrate from old key if present
  if (localStorage.getItem(OLD_STORAGE_KEY) !== null) {
    return migrateFromOldKey();
  }
  return "system";
}
```

**`applyColorTheme` function — the core of the system:**

```typescript
function applyColorTheme(preference: ColorThemePreference, suppressTransitions = false): void {
  const systemDark = getSystemDark();
  const resolvedId = resolveColorTheme(preference, systemDark);
  const definition = COLOR_THEME_DEFINITIONS[resolvedId];
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Set the data attribute for potential CSS-only styling hooks
  root.setAttribute("data-color-theme", resolvedId);

  // Apply .dark class for Tailwind's @variant dark scope
  root.classList.toggle("dark", definition.isDark);

  // Map ThemeColors keys to CSS variable names and set them
  const { colors } = definition;
  root.style.setProperty("--background", colors.background);
  root.style.setProperty("--foreground", colors.foreground);
  root.style.setProperty("--card", colors.card);
  root.style.setProperty("--card-foreground", colors.cardForeground);
  root.style.setProperty("--popover", colors.popover);
  root.style.setProperty("--popover-foreground", colors.popoverForeground);
  root.style.setProperty("--primary", colors.primary);
  root.style.setProperty("--primary-foreground", colors.primaryForeground);
  root.style.setProperty("--secondary", colors.secondary);
  root.style.setProperty("--secondary-foreground", colors.secondaryForeground);
  root.style.setProperty("--muted", colors.muted);
  root.style.setProperty("--muted-foreground", colors.mutedForeground);
  root.style.setProperty("--accent", colors.accent);
  root.style.setProperty("--accent-foreground", colors.accentForeground);
  root.style.setProperty("--destructive", colors.destructive);
  root.style.setProperty("--destructive-foreground", colors.destructiveForeground);
  root.style.setProperty("--border", colors.border);
  root.style.setProperty("--input", colors.input);
  root.style.setProperty("--ring", colors.ring);
  // New surface zone variables
  root.style.setProperty("--sidebar", colors.sidebar);
  root.style.setProperty("--sidebar-foreground", colors.sidebarForeground);
  root.style.setProperty("--sidebar-accent", colors.sidebarAccent);
  root.style.setProperty("--sidebar-accent-foreground", colors.sidebarAccentForeground);
  root.style.setProperty("--sidebar-border", colors.sidebarBorder);
  root.style.setProperty("--sidebar-ring", colors.sidebarRing);
  root.style.setProperty("--sidebar-primary", colors.sidebarPrimary);
  root.style.setProperty("--sidebar-primary-foreground", colors.sidebarPrimaryForeground);
  root.style.setProperty("--editor", colors.editor);
  root.style.setProperty("--editor-foreground", colors.editorForeground);
  root.style.setProperty("--terminal", colors.terminal);
  root.style.setProperty("--terminal-foreground", colors.terminalForeground);
  root.style.setProperty("--status-bar", colors.statusBar);
  root.style.setProperty("--status-bar-foreground", colors.statusBarForeground);

  if (suppressTransitions) {
    root.offsetHeight; // force reflow
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}
```

**Apply immediately on module load (like existing `useTheme.ts`):**

```typescript
// This runs synchronously when the module is first imported.
// If imported from <script type="module"> in <head>, it prevents flash.
applyColorTheme(getStoredPreference());
```

**`subscribe` function:**

```typescript
function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleMediaChange = (): void => {
    if (getStoredPreference() === "system") {
      applyColorTheme("system", true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleMediaChange);

  const handleStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) {
      applyColorTheme(getStoredPreference(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleMediaChange);
    window.removeEventListener("storage", handleStorage);
  };
}
```

**`getSnapshot` function (stable-reference optimization):**

```typescript
function getSnapshot(): { preference: ColorThemePreference; systemDark: boolean } {
  const preference = getStoredPreference();
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.preference === preference &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, systemDark };
  return lastSnapshot;
}
```

**`useColorTheme` hook:**

```typescript
export function useColorTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { preference, systemDark } = snapshot;

  const resolvedTheme: BuiltInColorTheme =
    preference === "system"
      ? (systemDark ? "t3-dark" : "t3-light")
      : preference;

  const setColorTheme = useCallback((next: ColorThemePreference): void => {
    localStorage.setItem(STORAGE_KEY, next);
    applyColorTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyColorTheme(preference);
  }, [preference]);

  return {
    colorTheme: preference,
    setColorTheme,
    resolvedColorTheme: resolvedTheme,
  } as const;
}
```

**Also export `applyColorTheme` for use in `ThreadTerminalDrawer.tsx`** when re-theming the xterm instance:

```typescript
export { applyColorTheme };
```

