import { type ReactNode } from "react";
import { useColorTheme } from "~/hooks/useColorTheme";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * Integrates the color theme system into the React tree. Ensures the theme
 * subscription is active and the DOM stays in sync with stored preferences.
 * Place this near the root of the component tree.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Calling useColorTheme here ensures the subscription is live and
  // the useEffect inside the hook keeps the DOM in sync on mount/change.
  useColorTheme();
  return <>{children}</>;
}

