import {
  BUILT_IN_COLOR_THEMES,
  COLOR_THEME_DEFINITIONS,
  type BuiltInColorTheme,
  type ColorThemePreference,
} from "@t3tools/shared/theme";
import { cn } from "~/lib/utils";

interface ThemeSelectorProps {
  value: ColorThemePreference;
  onChange: (next: ColorThemePreference) => void;
}

/**
 * Theme selector with color swatch previews for each built-in theme plus a
 * "System" option that follows the OS appearance setting.
 */
export function ThemeSelector({ value, onChange }: ThemeSelectorProps) {
  return (
    <div role="radiogroup" aria-label="Color theme" className="flex flex-col gap-3">
      <SystemThemeOption selected={value === "system"} onSelect={() => onChange("system")} />
      <div className="grid grid-cols-3 gap-2">
        {BUILT_IN_COLOR_THEMES.map((id) => (
          <ThemeCard
            key={id}
            id={id}
            selected={value === id}
            onSelect={() => onChange(id)}
          />
        ))}
      </div>
    </div>
  );
}

interface SystemThemeOptionProps {
  selected: boolean;
  onSelect: () => void;
}

function SystemThemeOption({ selected, onSelect }: SystemThemeOptionProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={onSelect}
      className={cn(
        "flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
    >
      <span className="flex flex-col">
        <span className="text-sm font-medium">System</span>
        <span className="text-xs">Follows your OS appearance setting.</span>
      </span>
      {selected ? (
        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Selected
        </span>
      ) : null}
    </button>
  );
}

interface ThemeCardProps {
  id: BuiltInColorTheme;
  selected: boolean;
  onSelect: () => void;
}

function ThemeCard({ id, selected, onSelect }: ThemeCardProps) {
  const definition = COLOR_THEME_DEFINITIONS[id];
  const { colors, label } = definition;

  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={onSelect}
      className={cn(
        "flex flex-col gap-2 rounded-xl border p-2 text-left transition-all",
        selected
          ? "border-primary/60 ring-2 ring-primary/25"
          : "border-border hover:border-primary/30",
      )}
    >
      {/* Mini app chrome preview — uses inline styles so swatches always show
          each theme's own palette, regardless of which theme is currently active. */}
      <div
        className="flex h-16 w-full overflow-hidden rounded-lg"
        style={{ background: colors.background }}
        aria-hidden="true"
      >
        {/* Sidebar strip */}
        <div className="h-full w-6 shrink-0" style={{ background: colors.sidebar }} />

        {/* Content area */}
        <div className="flex flex-1 flex-col gap-1 p-1.5">
          {/* Status bar strip */}
          <div className="h-1.5 w-full rounded-sm" style={{ background: colors.statusBar }} />

          {/* Simulated text lines */}
          <div className="flex flex-1 flex-col gap-0.5">
            <div
              className="h-1 rounded-sm"
              style={{ background: colors.border, opacity: 0.9 }}
            />
            <div
              className="h-1 w-3/4 rounded-sm"
              style={{ background: colors.border, opacity: 0.6 }}
            />
            <div
              className="h-1 w-1/2 rounded-sm"
              style={{ background: colors.accent, opacity: 0.7 }}
            />
          </div>

          {/* Primary color accent dot */}
          <div className="mt-auto flex gap-1">
            <div
              className="h-2 w-2 rounded-full"
              style={{ background: colors.primary }}
            />
          </div>
        </div>
      </div>

      {/* Label row */}
      <div className="flex items-center justify-between px-0.5">
        <span className="text-xs font-medium text-foreground">{label}</span>
        {selected ? (
          <span
            className="h-1.5 w-1.5 rounded-full bg-primary"
            aria-hidden="true"
          />
        ) : null}
      </div>
    </button>
  );
}

